INSERT INTO `services` (`id`, `name`, `slug`, `short_desc`, `description`, `image`, `icon`, `order`, `is_active`, `meta_title`, `meta_desc`, `og_image`, `created_at`, `updated_at`, `meta_keywords`, `gallery`, `specifications`, `faqs`, `brochure`, `price`, `sale_price`, `stock`, `weight`, `sku`, `product_category_id`, `is_featured`, `type`, `sold_count`, `views_count`, `unit`, `min_order`, `max_order`, `rating`) VALUES 
('1', 'Smart TV LED 4K 55 Inch', 'smart-tv-led-4k-55-inch', 'Smart TV 55 Inch dengan resolusi 4K UHD, HDR10+, dan sistem operasi Android TV terbaru untuk hiburan tanpa batas.', '<p>Hadirkan pengalaman bioskop di ruang keluarga Anda dengan Smart TV LED 4K 55 Inch. Dilengkapi teknologi HDR10+ untuk kontras menakjubkan dan warna yang lebih hidup. Sistem operasi Android TV memungkinkan Anda mengunduh ribuan aplikasi, streaming film favorit, dan menggunakan Google Assistant langsung dari remote Anda.</p><ul><li>Resolusi 4K UHD (3840 x 2160)</li><li>Android TV OS &amp; Google Assistant</li><li>Dolby Audio &amp; DTS Virtual:X</li><li>Bezeless Design</li></ul>', 'services/RTvYbGC9dF7rvDr1.webp', NULL, '0', '1', 'Smart TV LED 4K 55 Inch | Cyclevent', 'Jual Smart TV LED 4K 55 Inch di Indonesia. Distributor, Supplier, Agen, Smart TV LED 4K 55 Inch. Kami Menjual Smart TV LED 4K 55 Inch terlengkap dengan har...', 'services/og/og_ngGUviLy3ldn.webp', '2026-07-17 08:31:22', '2026-07-17 08:46:10', NULL, '[\"services\\/gallery\\/BVpXYiNv6PvsJkrA.webp\"]', '[{\"key\":\"Resolusi\",\"value\":\"4K Ultra HD (3840 x 2160)\"},{\"key\":\"Ukuran Layar\",\"value\":\"55 Inch\"},{\"key\":\"Sistem Operasi\",\"value\":\"Android TV\"},{\"key\":\"Konektivitas\",\"value\":\"Wi-Fi, Bluetooth, 3x HDMI, 2x USB\"},{\"key\":\"Daya\",\"value\":\"130 Watt\"}]', '[{\"q\":\"Apakah TV ini mendukung siaran digital (DVB-T2)?\",\"a\":\"Ya, TV ini sudah dilengkapi tuner DVB-T2 bawaan sehingga Anda bisa menikmati siaran TV digital tanpa perlu set-top box tambahan.\"},{\"q\":\"Berapa lama garansi panel layarnya?\",\"a\":\"Kami memberikan garansi resmi panel layar selama 3 tahun dan garansi sparepart selama 1 tahun.\"}]', NULL, '5500000', '4999000', '10', '15000', 'TV-55-4K', NULL, '0', 'product', '125', '0', NULL, '1', NULL, '0'),
('2', 'AC Split Inverter 1 PK Hemat Energi', 'ac-split-inverter-1-pk-hemat-energi', 'AC Inverter 1 PK yang mendinginkan ruangan lebih cepat dengan konsumsi listrik sangat irit hingga 60%.', '<p>Solusi pendingin udara terbaik untuk kamar atau ruang keluarga Anda. AC Split Inverter ini menggunakan kompresor pintar yang dapat menyesuaikan kecepatan pendinginan, sehingga menghemat listrik hingga 60% dibandingkan AC standar. Nikmati udara yang sejuk, bersih, dan bebas bakteri berkat filter anti-microbial bawaan.</p>', 'services/i9GwK2hvImsilOZU.webp', NULL, '1', '1', 'AC Split Inverter 1 PK Hemat Energi | Cyclevent', 'Jual AC Split Inverter 1 PK Hemat Energi di Indonesia. Distributor, Supplier, Agen, AC Split Inverter 1 PK Hemat Energi. Kami Menjual AC Split Inverter 1 P...', 'services/og/og_cpIhD8rEEpFr.webp', '2026-07-17 08:31:22', '2026-07-17 11:22:39', NULL, '[\"services\\/gallery\\/UJAJmvqWCTrfUAqc.webp\"]', '[{\"key\":\"Kapasitas Pendinginan\",\"value\":\"9000 BTU\\/h (1 PK)\"},{\"key\":\"Tipe Kompresor\",\"value\":\"Inverter\"},{\"key\":\"Konsumsi Daya\",\"value\":\"220W - 950W\"},{\"key\":\"Refrigerant\",\"value\":\"R32 (Ramah Lingkungan)\"},{\"key\":\"Fitur Tambahan\",\"value\":\"Filter Anti Bakteri, Auto Restart, Sleep Mode\"}]', '[{\"q\":\"Apakah harga sudah termasuk jasa pasang?\",\"a\":\"Belum. Harga yang tertera hanya untuk unit AC (Indoor & Outdoor). Anda bisa memesan Jasa Pasang AC secara terpisah di toko kami.\"},{\"q\":\"Berapa lama garansi kompresornya?\",\"a\":\"Garansi kompresor berlaku selama 10 tahun dari pabrik.\"}]', NULL, '4200000', '3850000', '25', '28000', 'AC-INV-1PK', NULL, '0', 'product', '840', '0', NULL, '1', NULL, '0'),
('3', 'Sofa Bed Minimalis Modern', 'sofa-bed-minimalis-modern', 'Sofa multifungsi yang elegan dan nyaman. Dapat direbahkan menjadi tempat tidur ekstra untuk tamu.', '<p>Sofa bed ini didesain khusus untuk Anda yang menyukai gaya minimalis dengan ruang terbatas. Pada siang hari, sofa ini berfungsi sebagai tempat duduk yang empuk dan stylish. Saat malam hari, Anda bisa mengubahnya menjadi tempat tidur nyaman hanya dengan satu tarikan. Dibuat dengan kerangka kayu solid dan busa high-density yang tidak mudah kempis.</p>', 'services/uqjPoouuarJNCgZJ.webp', NULL, '2', '1', 'Sofa Bed Minimalis Modern | Cyclevent', 'Jual Sofa Bed Minimalis Modern di Indonesia. Distributor, Supplier, Agen, Sofa Bed Minimalis Modern. Kami Menjual Sofa Bed Minimalis Modern terlengkap deng...', 'services/og/og_mmmuKP9xHY8N.webp', '2026-07-17 08:31:22', '2026-07-17 11:22:18', NULL, '[]', '[{\"key\":\"Dimensi Sofa\",\"value\":\"180 x 85 x 80 cm\"},{\"key\":\"Dimensi Bed\",\"value\":\"180 x 110 x 40 cm\"},{\"key\":\"Material Cover\",\"value\":\"Kain Fabric (Water Repellent)\"},{\"key\":\"Kerangka\",\"value\":\"Kayu Solid & Per Zigzag\"},{\"key\":\"Kapasitas Beban\",\"value\":\"Hingga 250 kg\"}]', '[{\"q\":\"Apakah cover bisa dilepas dan dicuci?\",\"a\":\"Cover tidak bisa dilepas, namun bahan yang digunakan adalah water repellent sehingga mudah dibersihkan menggunakan lap basah.\"},{\"q\":\"Apakah perakitannya sulit?\",\"a\":\"Sofa dikirim dalam keadaan hampir utuh. Anda hanya perlu memasang bagian kakinya saja (alat dan baut sudah disediakan).\"}]', NULL, '2500000', NULL, '5', '45000', 'SOFA-BED-M', NULL, '0', 'product', '56', '0', NULL, '1', NULL, '0'),
('4', 'Jasa Pasang AC Profesional', 'jasa-pasang-ac-profesional', 'Layanan instalasi AC oleh teknisi tersertifikasi, bergaransi pemasangan dan tanpa biaya tersembunyi.', '<p>Pastikan AC Anda terpasang dengan benar untuk menghindari kebocoran freon atau air. Teknisi kami sangat berpengalaman dan bersertifikat dalam melakukan instalasi AC berbagai merk. Pemasangan dilakukan secara rapi, cepat, dan aman.</p>', 'services/ulGD0nsf31cMlc9S.webp', NULL, '3', '1', 'Jasa Pasang AC Profesional | Cyclevent', 'Jual Jasa Pasang AC Profesional di Indonesia. Distributor, Supplier, Agen, Jasa Pasang AC Profesional. Kami Menjual Jasa Pasang AC Profesional terlengkap d...', 'services/og/og_Sj5n8W9ZuWco.webp', '2026-07-17 08:31:22', '2026-07-20 08:16:22', NULL, '[]', '[{\"key\":\"Cakupan Layanan\",\"value\":\"Jabodetabek\"},{\"key\":\"Termasuk\",\"value\":\"Pipa AC 3m, Kabel Listrik 3m, Bracket, Ducktape\"},{\"key\":\"Tidak Termasuk\",\"value\":\"Bongkar AC lama, penambahan pipa jika lebih dari 3m\"},{\"key\":\"Garansi Pasang\",\"value\":\"30 Hari (Bocor Air \\/ Freon)\"}]', '[{\"q\":\"Bagaimana jika pemasangan butuh pipa lebih dari 3 meter?\",\"a\":\"Akan dikenakan biaya tambahan per meter yang akan dibayarkan langsung ke teknisi setelah pemasangan selesai.\"},{\"q\":\"Apakah bisa mengatur jadwal pemasangan?\",\"a\":\"Tentu. Setelah pembayaran berhasil, tim CS kami akan menghubungi Anda untuk mengatur jadwal kedatangan teknisi sesuai ketersediaan waktu Anda.\"}]', NULL, '0', NULL, '10', '0', 'JASA-PASANG-AC', NULL, '0', 'service', '1250', '0', NULL, '1', NULL, '0'),
('5', 'Jasa Pembersihan & Servis AC Tuntas', 'jasa-pembersihan-servis-ac-tuntas', 'Cuci AC profesional agar udara kembali segar, dingin maksimal, dan hemat listrik.', '<p>AC yang kotor tidak hanya membuat ruangan kurang dingin, tetapi juga mengonsumsi lebih banyak listrik dan menyebarkan bakteri. Layanan cuci AC kami meliputi pembersihan unit indoor (evaporator, filter, blower) dan outdoor (kondensor) menggunakan mesin jet cleaner. Hasilnya, AC Anda akan kembali dingin seperti baru.</p>', 'services/EUd25j3eeecVHr9q.webp', NULL, '4', '1', 'Jasa Pembersihan & Servis AC Tuntas | Cyclevent', 'Jual Jasa Pembersihan & Servis AC Tuntas di Indonesia. Distributor, Supplier, Agen, Jasa Pembersihan & Servis AC Tuntas. Kami Menjual Jasa Pembersihan & Se...', 'services/og/og_vnOszzCSVM7u.webp', '2026-07-17 08:31:22', '2026-07-20 08:16:26', NULL, '[]', '[{\"key\":\"Cakupan Layanan\",\"value\":\"Jabodetabek\"},{\"key\":\"Pengerjaan\",\"value\":\"Cuci Indoor, Cuci Outdoor, Cek Freon, Cek Ampere Kompresor\"},{\"key\":\"Garansi\",\"value\":\"14 Hari (Bocor Air)\"}]', '[{\"q\":\"Apakah termasuk isi freon?\",\"a\":\"Biaya ini hanya untuk cuci AC. Jika teknisi menemukan kekurangan freon, akan diinfokan terlebih dahulu beserta biayanya sebelum dilakukan penambahan.\"},{\"q\":\"Seberapa sering AC harus dicuci?\",\"a\":\"Idealnya AC dicuci setiap 3-4 bulan sekali tergantung intensitas pemakaian dan kondisi debu di lingkungan sekitar.\"}]', NULL, '0', NULL, '10', '0', 'JASA-CUCI-AC', NULL, '0', 'service', '3210', '0', NULL, '1', NULL, '0');
