DROP TABLE IF EXISTS `gallery_projects`;
CREATE TABLE `gallery_projects` (`id` INT PRIMARY KEY AUTO_INCREMENT not null, `title` VARCHAR(255) not null, `description` text, `image` VARCHAR(255) not null, `alt_text` VARCHAR(255), `category` VARCHAR(255), `client` VARCHAR(255), `location` VARCHAR(255), `year` INT, `order` INT not null default '0', `is_active` tinyint(1) not null default '1', `created_at` datetime, `updated_at` datetime, `slug` VARCHAR(255), `meta_title` VARCHAR(255), `meta_desc` text, `og_image` VARCHAR(255), `tags` VARCHAR(255), `is_featured` tinyint(1) not null default '0', `content` text, `meta_keywords` VARCHAR(255), `is_published` tinyint(1) not null default '1');

DROP TABLE IF EXISTS `clients`;
CREATE TABLE `clients` (`id` INT PRIMARY KEY AUTO_INCREMENT not null, `name` VARCHAR(255) not null, `logo` VARCHAR(255), `city` VARCHAR(255), `industry` VARCHAR(255), `order` INT not null default '0', `is_active` tinyint(1) not null default '1', `created_at` datetime, `updated_at` datetime, `alt_text` VARCHAR(255));

DROP TABLE IF EXISTS `testimonials`;
CREATE TABLE `testimonials` (`id` INT PRIMARY KEY AUTO_INCREMENT not null, `name` VARCHAR(255) not null, `company` VARCHAR(255), `position` VARCHAR(255), `content` text not null, `rating` INT not null default '5', `photo` VARCHAR(255), `is_active` tinyint(1) not null default '1', `order` INT not null default '0', `created_at` datetime, `updated_at` datetime);

DROP TABLE IF EXISTS `analytics_events`;
CREATE TABLE `analytics_events` (`id` INT PRIMARY KEY AUTO_INCREMENT not null, `event_type` VARCHAR(255) not null, `page_url` VARCHAR(255), `page_title` VARCHAR(255), `referrer` VARCHAR(255), `user_agent` text, `ip_address` VARCHAR(255), `country` VARCHAR(255), `device_type` VARCHAR(255), `created_at` datetime not null default CURRENT_TIMESTAMP, `updated_at` datetime);


DROP TABLE IF EXISTS `wa_settings`;
CREATE TABLE `wa_settings` (`id` INT PRIMARY KEY AUTO_INCREMENT not null, `label` VARCHAR(255) not null, `nomor_wa` VARCHAR(255) not null, `template_pesan` text not null, `is_active` tinyint(1) not null default '1', `is_primary` tinyint(1) not null default '0', `order` INT not null default '0', `created_at` datetime, `updated_at` datetime);


DROP TABLE IF EXISTS `leads`;
CREATE TABLE `leads` (`id` INT PRIMARY KEY AUTO_INCREMENT not null, `name` VARCHAR(255) not null, `company` VARCHAR(255), `email` VARCHAR(255), `phone` VARCHAR(255) not null, `product` VARCHAR(255), `message` text, `source` VARCHAR(255) not null default 'website', `page_url` VARCHAR(255), `ip_address` VARCHAR(255), `device_type` VARCHAR(255), `status` VARCHAR(255) not null default 'new', `notes` text, `wa_number` VARCHAR(255), `created_at` datetime, `updated_at` datetime, `utm_source` VARCHAR(255), `utm_medium` VARCHAR(255), `utm_campaign` VARCHAR(255), `utm_term` VARCHAR(255), `utm_content` VARCHAR(255));


DROP TABLE IF EXISTS `hero_slides`;
CREATE TABLE `hero_slides` (`id` INT PRIMARY KEY AUTO_INCREMENT not null, `created_at` datetime, `updated_at` datetime, `title` VARCHAR(255), `description` text, `icon` VARCHAR(255), `image` VARCHAR(255), `button_text` VARCHAR(255), `button_url` VARCHAR(255), `order` INT not null default '0', `is_active` tinyint(1) not null default '1', `position` VARCHAR(255) not null default 'hero', `bg_color` VARCHAR(255));


DROP TABLE IF EXISTS `article_translations`;
CREATE TABLE `article_translations` (`id` INT PRIMARY KEY AUTO_INCREMENT not null, `article_id` INT not null, `locale` VARCHAR(255) not null, `title` VARCHAR(255), `excerpt` text, `content` text, `faqs` text, `cta_button` text, `meta_title` VARCHAR(255), `meta_desc` text, `meta_keywords` VARCHAR(255), `is_complete` tinyint(1) not null default '0', `translated_by` VARCHAR(255), `created_at` datetime, `updated_at` datetime, `featured_snippet` text, `thumbnail_alt` VARCHAR(255), foreign key(`article_id`) references `articles`(`id`) on delete cascade);

DROP TABLE IF EXISTS `authors`;
CREATE TABLE `authors` (`id` INT PRIMARY KEY AUTO_INCREMENT not null, `name` VARCHAR(255) not null, `photo` VARCHAR(255), `social_links` text, `created_at` datetime, `updated_at` datetime, `slug` VARCHAR(255));


DROP TABLE IF EXISTS `author_translations`;
CREATE TABLE `author_translations` (`id` INT PRIMARY KEY AUTO_INCREMENT not null, `author_id` INT not null, `locale` VARCHAR(255) not null, `bio` text, `created_at` datetime, `updated_at` datetime, foreign key(`author_id`) references `authors`(`id`) on delete cascade);


DROP TABLE IF EXISTS `articles`;
CREATE TABLE `articles` (`id` INT PRIMARY KEY AUTO_INCREMENT not null, `slug` VARCHAR(255) not null, `image` VARCHAR(255), `alt_text` VARCHAR(255), `category` VARCHAR(255), `tags` text, `is_published` tinyint(1) not null default '0', `published_at` datetime, `views` INT not null default '0', `og_image` VARCHAR(255), `author` VARCHAR(255) default 'Admin', `created_at` datetime, `updated_at` datetime, `show_toc` tinyint(1) not null default '0', `author_id` INT, foreign key(`author_id`) references `authors`(`id`) on delete set null);

DROP TABLE IF EXISTS `product_categories`;
CREATE TABLE `product_categories` (`id` INT PRIMARY KEY AUTO_INCREMENT not null, `name` VARCHAR(255) not null, `slug` VARCHAR(255) not null, `description` text, `image` VARCHAR(255), `is_active` tinyint(1) not null default '1', `order` INT not null default '0', `created_at` datetime, `updated_at` datetime);

DROP TABLE IF EXISTS `services`;
CREATE TABLE `services` (`id` INT PRIMARY KEY AUTO_INCREMENT not null, `name` VARCHAR(255) not null, `slug` VARCHAR(255) not null, `short_desc` text, `description` text, `image` VARCHAR(255), `icon` VARCHAR(255), `order` INT not null default '0', `is_active` tinyint(1) not null default '1', `meta_title` VARCHAR(255), `meta_desc` text, `og_image` VARCHAR(255), `created_at` datetime, `updated_at` datetime, `meta_keywords` VARCHAR(255), `gallery` text, `specifications` text, `faqs` text, `brochure` VARCHAR(255), `price` numeric not null default '0', `sale_price` numeric, `stock` INT not null default '0', `weight` INT not null default '0', `sku` VARCHAR(255), `product_category_id` INT, `is_featured` tinyint(1) not null default '0', `type` VARCHAR(255)  not null default 'product', `sold_count` INT not null default '0', `views_count` INT not null default '0', `unit` VARCHAR(255), `min_order` INT not null default '1', `max_order` INT, `rating` numeric default '0', foreign key(`product_category_id`) references `product_categories`(`id`) on delete set null);


DROP TABLE IF EXISTS `product_variant_options`;
CREATE TABLE `product_variant_options` (`id` INT PRIMARY KEY AUTO_INCREMENT not null, `product_id` INT not null, `name` VARCHAR(255) not null, `created_at` datetime, `updated_at` datetime, foreign key(`product_id`) references `services`(`id`) on delete cascade);

DROP TABLE IF EXISTS `product_variant_values`;
CREATE TABLE `product_variant_values` (`id` INT PRIMARY KEY AUTO_INCREMENT not null, `variant_option_id` INT not null, `value` VARCHAR(255) not null, `price_adjustment` numeric not null default '0', `stock` INT, `sku` VARCHAR(255), `created_at` datetime, `updated_at` datetime, foreign key(`variant_option_id`) references `product_variant_options`(`id`) on delete cascade);

DROP TABLE IF EXISTS `addresses`;
CREATE TABLE `addresses` (`id` INT PRIMARY KEY AUTO_INCREMENT not null, `user_id` INT not null, `label` VARCHAR(255) not null default 'Rumah', `receiver_name` VARCHAR(255) not null, `phone` VARCHAR(255) not null, `province` VARCHAR(255) not null, `city` VARCHAR(255) not null, `district` VARCHAR(255) not null, `postal_code` VARCHAR(255) not null, `full_address` text not null, `is_default` tinyint(1) not null default '0', `created_at` datetime, `updated_at` datetime, `village` VARCHAR(255), `latitude` numeric, `longitude` numeric, foreign key(`user_id`) references `users`(`id`) on delete cascade);


DROP TABLE IF EXISTS `carts`;
CREATE TABLE `carts` (`id` INT PRIMARY KEY AUTO_INCREMENT not null, `user_id` INT, `session_id` VARCHAR(255), `product_id` INT not null, `variant_value_id` INT, `qty` INT not null default '1', `created_at` datetime, `updated_at` datetime, foreign key(`user_id`) references `users`(`id`) on delete set null, foreign key(`product_id`) references `services`(`id`) on delete cascade, foreign key(`variant_value_id`) references `product_variant_values`(`id`) on delete set null);


DROP TABLE IF EXISTS `orders`;
CREATE TABLE `orders` (`id` INT PRIMARY KEY AUTO_INCREMENT not null, `order_number` VARCHAR(255) not null, `user_id` INT not null, `status` VARCHAR(255)  not null default 'pending', `subtotal` numeric not null default '0', `shipping_cost` numeric not null default '0', `discount` numeric not null default '0', `total` numeric not null default '0', `shipping_address` text not null, `notes` text, `created_at` datetime, `updated_at` datetime, `deleted_at` datetime, foreign key(`user_id`) references `users`(`id`) on delete restrict);

DROP TABLE IF EXISTS `order_items`;
CREATE TABLE `order_items` (`id` INT PRIMARY KEY AUTO_INCREMENT not null, `order_id` INT not null, `product_id` INT, `variant_value_id` INT, `product_name` VARCHAR(255) not null, `variant_name` VARCHAR(255), `price` numeric not null, `qty` INT not null, `subtotal` numeric not null, `created_at` datetime, `updated_at` datetime, foreign key(`order_id`) references `orders`(`id`) on delete cascade, foreign key(`product_id`) references `services`(`id`) on delete set null, foreign key(`variant_value_id`) references `product_variant_values`(`id`) on delete set null);

DROP TABLE IF EXISTS `payments`;
CREATE TABLE `payments` (`id` INT PRIMARY KEY AUTO_INCREMENT not null, `order_id` INT not null, `payment_number` VARCHAR(255) not null, `method` VARCHAR(255), `gateway` VARCHAR(255) not null default 'midtrans', `status` VARCHAR(255)  not null default 'pending', `amount` numeric not null, `midtrans_transaction_id` VARCHAR(255), `midtrans_token` text, `midtrans_redirect_url` text, `paid_at` datetime, `expired_at` datetime, `raw_response` text, `created_at` datetime, `updated_at` datetime, foreign key(`order_id`) references `orders`(`id`) on delete cascade);

DROP TABLE IF EXISTS `shipments`;
CREATE TABLE `shipments` (`id` INT PRIMARY KEY AUTO_INCREMENT not null, `order_id` INT not null, `courier_name` VARCHAR(255) not null, `courier_service` VARCHAR(255), `tracking_number` VARCHAR(255), `status` VARCHAR(255)  not null default 'pending', `estimated_delivery` date, `shipped_at` datetime, `delivered_at` datetime, `raw_tracking` text, `created_at` datetime, `updated_at` datetime, foreign key(`order_id`) references `orders`(`id`) on delete cascade);

DROP TABLE IF EXISTS `wishlists`;
CREATE TABLE `wishlists` (`id` INT PRIMARY KEY AUTO_INCREMENT not null, `user_id` INT not null, `product_id` INT not null, `created_at` datetime, `updated_at` datetime, foreign key(`user_id`) references `users`(`id`) on delete cascade, foreign key(`product_id`) references `services`(`id`) on delete cascade);

DROP TABLE IF EXISTS `coupons`;
CREATE TABLE `coupons` (`id` INT PRIMARY KEY AUTO_INCREMENT not null, `code` VARCHAR(255) not null, `type` VARCHAR(255)  not null default 'fixed', `value` numeric not null, `min_purchase` numeric not null default '0', `max_discount` numeric, `usage_limit` INT, `used_count` INT not null default '0', `is_active` tinyint(1) not null default '1', `started_at` datetime, `expired_at` datetime, `created_at` datetime, `updated_at` datetime);

DROP TABLE IF EXISTS `coupon_usages`;
CREATE TABLE `coupon_usages` (`id` INT PRIMARY KEY AUTO_INCREMENT not null, `coupon_id` INT not null, `order_id` INT not null, `user_id` INT not null, `discount_amount` numeric not null, `created_at` datetime, `updated_at` datetime, foreign key(`coupon_id`) references `coupons`(`id`) on delete cascade, foreign key(`order_id`) references `orders`(`id`) on delete cascade, foreign key(`user_id`) references `users`(`id`) on delete cascade);

DROP TABLE IF EXISTS `usp_items`;
CREATE TABLE `usp_items` (`id` INT PRIMARY KEY AUTO_INCREMENT not null, `icon_type` VARCHAR(255) not null default 'emoji', `icon_value` VARCHAR(255), `label` VARCHAR(255) not null, `sort_order` INT not null default '0', `is_active` tinyint(1) not null default '1', `created_at` datetime, `updated_at` datetime);


DROP TABLE IF EXISTS `category_items`;
CREATE TABLE `category_items` (`id` INT PRIMARY KEY AUTO_INCREMENT not null, `icon_type` VARCHAR(255) not null default 'emoji', `icon_value` VARCHAR(255), `name` VARCHAR(255) not null, `url` VARCHAR(255), `badge` VARCHAR(255), `badge_color` VARCHAR(255), `sort_order` INT not null default '0', `is_active` tinyint(1) not null default '1', `created_at` datetime, `updated_at` datetime);


DROP TABLE IF EXISTS `couriers`;
CREATE TABLE `couriers` (`id` INT PRIMARY KEY AUTO_INCREMENT not null, `name` VARCHAR(255) not null, `code` VARCHAR(255) not null, `type` VARCHAR(255) not null default 'expedition', `logo` VARCHAR(255), `is_active` tinyint(1) not null default '1', `order` INT not null default '0', `created_at` datetime, `updated_at` datetime);


DROP TABLE IF EXISTS `promo_sections`;
CREATE TABLE `promo_sections` (`id` INT PRIMARY KEY AUTO_INCREMENT not null, `title` VARCHAR(255) not null, `subtitle` VARCHAR(255), `banner` VARCHAR(255), `view_all_url` VARCHAR(255), `sort_order` INT not null default '0', `is_active` tinyint(1) not null default '1', `created_at` datetime, `updated_at` datetime, `selection_type` VARCHAR(255) not null default 'manual', `category_id` INT, `start_time` datetime, `end_time` datetime, `bg_color_1` VARCHAR(255), `bg_color_2` VARCHAR(255), `logo` VARCHAR(255));


DROP TABLE IF EXISTS `promo_section_service`;
CREATE TABLE `promo_section_service` (`id` INT PRIMARY KEY AUTO_INCREMENT not null, `promo_section_id` INT not null, `service_id` INT not null, `sort_order` INT not null default '0', foreign key(`promo_section_id`) references `promo_sections`(`id`) on delete cascade, foreign key(`service_id`) references `services`(`id`) on delete cascade);


SET FOREIGN_KEY_CHECKS = 1;
